// AppIcon: renderiza um SVG do dicionário ou cai pra emoji se não houver.
// shadow=true adiciona drop-shadow sutil pra dar aparência iOS native.
export const AppIcon = ({ name, size = 20, mr = 5, shadow = true }) => {
  const norm = (name || "").replace(/️/g, "");
  const icon = APP_ICONS[norm] || APP_ICONS[name];
  if (!icon) return <span style={{ fontSize: size }}>{name}</span>;
  return (
    <span
      className="app-icon-svg"
      style={{
        display: "inline-flex",
        alignItems: "center",
        justifyContent: "center",
        width: size,
        height: size,
        marginRight: mr,
        flexShrink: 0,
        verticalAlign: "middle",
        filter: shadow
          ? "drop-shadow(0 1px 2px rgba(0,0,0,0.25)) drop-shadow(0 0.5px 1px rgba(0,0,0,0.15))"
          : "none",
      }}
    >
      {icon}
    </span>
  );
};

// IconText: separa emoji inicial do resto do texto, renderiza o emoji
// como AppIcon (SVG) e o resto como texto. Usado em toasts e status
// messages onde "✅ Salvo" deve render o ✅ como SVG bonito.
export const IconText = ({ text, size = 16, gap = 5, style }) => {
  if (!text) return null;
  const s = String(text);
  try {
    const seg = new Intl.Segmenter("pt-BR", { granularity: "grapheme" });
    const parts = [...seg.segment(s)];
    let iconEnd = 0;
    while (iconEnd < parts.length) {
      const ch = parts[iconEnd].segment;
      if (/^\s$/.test(ch)) break;
      const cp = ch.codePointAt(0);
      const isEmoji =
        (cp >= 0x1f300 && cp <= 0x1faff) ||
        (cp >= 0x2600 && cp <= 0x27bf) ||
        (cp >= 0x1f900 && cp <= 0x1f9ff) ||
        (cp >= 0x2190 && cp <= 0x21ff);
      if (!isEmoji) break;
      iconEnd++;
    }
    if (iconEnd === 0) return <span style={style}>{s}</span>;
    const iconSegs = parts.slice(0, iconEnd).map((p) => p.segment);
    const rest = parts
      .slice(iconEnd)
      .map((p) => p.segment)
      .join("")
      .replace(/^\s+/, "");
    return (
      <span style={{ display: "inline-flex", alignItems: "center", gap, ...style }}>
        {iconSegs.map((e, i) => <AppIcon key={i} name={e} size={size} mr={0} />)}
        {rest && <span>{rest}</span>}
      </span>
    );
  } catch (e) {
    return <span style={style}>{s}</span>;
  }
};

// Export do dicionário pra Cd_ (que checa hasSvg via APP_ICONS[iconKey]).
export { APP_ICONS };
